import Link from "next/link";
import Image from "next/image";
import { cn } from "@/lib/utils";
import { urlFor } from "@/sanity/lib/image";

interface BlogCardProps {
    title: string;
    excerpt: string;
    category: string;
    date: string;
    slug: string;
    mainImage?: any;
    className?: string;
}

export default function BlogCard({ title, excerpt, category, date, slug, mainImage, className }: BlogCardProps) {
    return (
        <Link
            href={`/blog/${slug}`}
            className={cn(
                "group flex flex-col bg-white transition-all duration-500",
                className
            )}
        >
            <div className="relative aspect-[16/10] overflow-hidden rounded-[2.5rem] bg-slate-50 border border-slate-100 group-hover:border-blue-100 transition-all duration-500 mb-8">
                {mainImage ? (
                    <Image
                        src={urlFor(mainImage).url()}
                        alt={title}
                        fill
                        className="object-cover group-hover:scale-110 transition-transform duration-1000 ease-out"
                    />
                ) : (
                    <div className="absolute inset-0 bg-linear-to-tr from-blue-50/50 to-indigo-50/50 group-hover:scale-110 transition-transform duration-1000" />
                )}

                <div className="absolute top-6 left-6 px-4 py-2 bg-white rounded-full text-[9px] font-body font-black text-blue-600 uppercase tracking-[0.2em] shadow-sm">
                    {category}
                </div>
            </div>

            <div className="flex flex-col flex-1 px-2">
                <div className="text-[10px] font-body font-bold text-slate-400 uppercase tracking-widest mb-4">
                    {date} / 5 Min Read
                </div>

                <h3 className="text-3xl font-heading font-black text-slate-900 mb-4 leading-[1.1] transition-colors group-hover:text-blue-600">
                    {title}
                </h3>

                <p className="text-slate-500 font-body text-base leading-relaxed line-clamp-2 mb-8 flex-1">
                    {excerpt}
                </p>

                <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-900 font-black group-hover:bg-blue-600 group-hover:text-white transition-all">
                        →
                    </div>
                    <span className="text-[10px] font-body font-black uppercase tracking-widest text-slate-900 group-hover:text-blue-600 transition-colors">
                        View Full Story
                    </span>
                </div>
            </div>
        </Link>
    );
}
